using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 (EF9): Discriminator JSON property renamed from
            // "Discriminator" to "$type".  Existing documents and direct SQL queries
            // (e.g. WHERE c.Discriminator = 'Product') rely on the old name.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 (EF9): id synthesis changed from "Product|123"
            // to just "123".  Existing 500K documents use the old format — preserve
            // it so reads, writes, and point-lookups remain compatible.
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<EF8CosmosIdValueGenerator>();

            // BREAKING CHANGE 3 (EF9): HasIndex now throws for the Cosmos provider
            // (was silently ignored in EF8).  Cosmos does not support EF-managed
            // secondary indexes.  Use Cosmos indexing policy instead.
            // REMOVED: b.HasIndex(p => p.Sku);
        });
    }
}

/// <summary>
/// Generates Cosmos id values in EF8's "Discriminator|PrimaryKey" format
/// so new documents stay compatible with the 500K existing ones.
/// </summary>
class EF8CosmosIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
                            ?? entry.Metadata.ShortName();
        var pk = entry.Property("Id").CurrentValue;
        return $"{discriminator}|{pk}";
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }
}

